export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = Math.max(0, maxTokens);
    this.tokens = this.maxTokens;
    this.refillRate = Math.max(0, refillRate);
    this.lastRefill = Date.now();
  }

  tryConsume(): boolean {
    this.refill();

    if (this.tokens > 0) {
      this.tokens = Math.max(0, this.tokens - 1);
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this.lastRefill);

    if (elapsed <= 0) {
      return;
    }

    const newTokens = (elapsed / 1000) * this.refillRate;
    this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);
    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];
export type Filter = (record: Record) => boolean;

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((filter) => filter(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.length === 0 || filters.some((filter) => filter(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];

    if (this.filters.length > 0) {
      result = result.filter((record) => this.filters.every((filter) => filter(record)));
    }

    for (const stage of this.stages) {
      result = stage(result);
    }

    return result;
  }
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  field?: string;

  constructor(message: string, field?: string) {
    super(message);
    this.name = "CronParseError";
    this.field = field;
    Object.setPrototypeOf(this, CronParseError.prototype);
  }
}

type FieldConfig = {
  name: string;
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "day-of-month", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "day-of-week", min: 0, max: 6 },
];

function parseNumber(value: string, field: FieldConfig): number {
  if (!/^\d+$/.test(value)) {
    throw new CronParseError(`Invalid value "${value}" in ${field.name}`, field.name);
  }
  const num = Number(value);
  if (!Number.isInteger(num) || num < field.min || num > field.max) {
    throw new CronParseError(
      `Value "${value}" out of range for ${field.name} (${field.min}-${field.max})`,
      field.name
    );
  }
  return num;
}

function rangeValues(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseStep(value: string, field: FieldConfig): number[] {
  const parts = value.split("/");
  if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
    throw new CronParseError(`Invalid step syntax "${value}" in ${field.name}`, field.name);
  }

  const base = parts[0];
  const stepStr = parts[1];

  if (!/^\d+$/.test(stepStr)) {
    throw new CronParseError(`Invalid step value "${stepStr}" in ${field.name}`, field.name);
  }

  const step = Number(stepStr);
  if (!Number.isInteger(step) || step <= 0) {
    throw new CronParseError(`Step must be a positive integer in ${field.name}`, field.name);
  }

  if (base === "*") {
    return rangeValues(field.min, field.max, step);
  }

  const rangeParts = base.split("-");
  if (rangeParts.length !== 2 || rangeParts[0] === "" || rangeParts[1] === "") {
    throw new CronParseError(`Invalid range with step syntax "${value}" in ${field.name}`, field.name);
  }

  const start = parseNumber(rangeParts[0], field);
  const end = parseNumber(rangeParts[1], field);

  if (start > end) {
    throw new CronParseError(`Range start greater than end in ${field.name}`, field.name);
  }

  return rangeValues(start, end, step);
}

function parseRange(value: string, field: FieldConfig): number[] {
  const parts = value.split("-");
  if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
    throw new CronParseError(`Invalid range syntax "${value}" in ${field.name}`, field.name);
  }

  const start = parseNumber(parts[0], field);
  const end = parseNumber(parts[1], field);

  if (start > end) {
    throw new CronParseError(`Range start greater than end in ${field.name}`, field.name);
  }

  return rangeValues(start, end, 1);
}

function parseSinglePart(value: string, field: FieldConfig): number[] {
  if (value === "*") {
    return rangeValues(field.min, field.max, 1);
  }

  if (value.includes("/")) {
    return parseStep(value, field);
  }

  if (value.includes("-")) {
    return parseRange(value, field);
  }

  return [parseNumber(value, field)];
}

function parseField(value: string, field: FieldConfig): number[] {
  if (value.trim() === "") {
    throw new CronParseError(`Empty ${field.name} field`, field.name);
  }

  const parts = value.split(",");
  const result = new Set<number>();

  for (const part of parts) {
    if (part === "") {
      throw new CronParseError(`Invalid list syntax "${value}" in ${field.name}`, field.name);
    }
    for (const num of parseSinglePart(part, field)) {
      result.add(num);
    }
  }

  return Array.from(result).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(`Expected 5 fields, got ${fields.length}`);
  }

  return {
    minutes: parseField(fields[0], FIELD_CONFIGS[0]),
    hours: parseField(fields[1], FIELD_CONFIGS[1]),
    daysOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    months: parseField(fields[3], FIELD_CONFIGS[3]),
    daysOfWeek: parseField(fields[4], FIELD_CONFIGS[4]),
    original: expression,
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function success(status: number, data: unknown): Response {
  return { status, body: { success: true, data } };
}

function error(status: number, message: string): Response {
  return { status, body: { success: false, error: message } };
}

function requireAuth(req: Request): Response | null {
  const token = req.headers["authorization"];
  if (!token) return error(401, "Authorization required");
  if (token !== "Bearer valid-token") return error(401, "Invalid token");
  return null;
}

function requireBody(req: Request): Response | Record<string, unknown> {
  if (!req.body) return error(400, "Request body is required");
  return req.body as Record<string, unknown>;
}

function requireIdParam(req: Request): Response | string {
  const id = req.params["id"];
  if (!id) return error(400, "Validation failed: id parameter is required");
  return id;
}

function validateNameForCreate(data: Record<string, unknown>): Response | string {
  const name = data["name"];
  if (!name || typeof name !== "string") {
    return error(400, "Validation failed: name is required");
  }
  return name;
}

function getItemOrNotFound(id: string): Response | Item {
  const item = store.get(id);
  return item ? item : error(404, "Item not found");
}

function handleGet(req: Request): Response {
  const id = req.params["id"];
  if (!id) return success(200, Array.from(store.values()));
  const item = getItemOrNotFound(id);
  return isResponse(item) ? item : success(200, item);
}

function handlePost(req: Request): Response {
  const body = requireBody(req);
  if (isResponse(body)) return body;
  const name = validateNameForCreate(body);
  if (isResponse(name)) return name;
  const id = body["id"] as string | undefined;
  if (id && store.has(id)) return error(409, "Item already exists");
  const newId = id || `item-${Date.now()}`;
  const now = Date.now();
  const item: Item = { id: newId, name, status: "active", createdAt: now, updatedAt: now };
  store.set(newId, item);
  return success(201, item);
}

function handlePut(req: Request): Response {
  const body = requireBody(req);
  if (isResponse(body)) return body;
  const id = requireIdParam(req);
  if (isResponse(id)) return id;
  const item = getItemOrNotFound(id);
  if (isResponse(item)) return item;
  const updated: Item = { ...item, updatedAt: Date.now() };
  if (body["name"] && typeof body["name"] === "string") updated.name = body["name"] as string;
  if (body["status"] && (body["status"] === "active" || body["status"] === "archived")) {
    updated.status = body["status"] as "active" | "archived";
  }
  store.set(id, updated);
  return success(200, updated);
}

function handleDelete(req: Request): Response {
  const id = requireIdParam(req);
  if (isResponse(id)) return id;
  const item = getItemOrNotFound(id);
  if (isResponse(item)) return item;
  store.delete(id);
  return success(200, { deleted: id });
}

function isResponse(value: unknown): value is Response {
  return !!value && typeof value === "object" && "status" in value && "body" in value;
}

export function handleRequest(req: Request): Response {
  const authError = requireAuth(req);
  if (authError) return authError;

  switch (req.method) {
    case "GET":
      return handleGet(req);
    case "POST":
      return handlePost(req);
    case "PUT":
      return handlePut(req);
    case "DELETE":
      return handleDelete(req);
    default:
      return error(405, "Method not allowed");
  }
}

import { describe, it, expect } from "vitest";
import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  it("returns a new object and does not mutate the target", () => {
    const target = {
      a: 1,
      nested: { x: 1, y: 2 },
    };
    const source = {
      b: 2,
      nested: { y: 3, z: 4 },
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      a: 1,
      b: 2,
      nested: { x: 1, y: 3, z: 4 },
    });
    expect(result).not.toBe(target);
    expect(target).toEqual({
      a: 1,
      nested: { x: 1, y: 2 },
    });
    expect(source).toEqual({
      b: 2,
      nested: { y: 3, z: 4 },
    });
  });

  it("recursively merges nested plain objects across multiple levels", () => {
    const target = {
      level1: {
        keep: true,
        level2: {
          a: 1,
          level3: {
            oldValue: "target",
            unchanged: "yes",
          },
        },
      },
    };

    const source = {
      level1: {
        level2: {
          b: 2,
          level3: {
            oldValue: "source",
            newValue: "added",
          },
        },
      },
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      level1: {
        keep: true,
        level2: {
          a: 1,
          b: 2,
          level3: {
            oldValue: "source",
            unchanged: "yes",
            newValue: "added",
          },
        },
      },
    });

    expect(result.level1).not.toBe(target.level1);
    expect(result.level1.level2).not.toBe(target.level1.level2);
    expect(result.level1.level2.level3).not.toBe(target.level1.level2.level3);
  });

  it("replaces arrays instead of merging them and clones the source array", () => {
    const sourceArray = [{ id: 2 }, { id: 3 }];
    const target = {
      items: [{ id: 1 }],
      nested: {
        arr: [1, 2, 3],
      },
    };
    const source = {
      items: sourceArray,
      nested: {
        arr: [4, 5],
      },
    };

    const result = deepMerge(target, source);

    expect(result.items).toEqual([{ id: 2 }, { id: 3 }]);
    expect(result.nested.arr).toEqual([4, 5]);
    expect(result.items).not.toBe(target.items);
    expect(result.items).not.toBe(sourceArray);
    expect(result.nested.arr).not.toBe(target.nested.arr);
    expect(result.nested.arr).not.toBe(source.nested.arr);

    sourceArray.push({ id: 4 });
    expect(result.items).toEqual([{ id: 2 }, { id: 3 }]);
  });

  it("clones Date objects from the source", () => {
    const targetDate = new Date("2020-01-01T00:00:00.000Z");
    const sourceDate = new Date("2024-05-06T07:08:09.000Z");

    const target = { created: targetDate };
    const source = { created: sourceDate };

    const result = deepMerge(target, source);

    expect(result.created).toBeInstanceOf(Date);
    expect((result.created as Date).getTime()).toBe(sourceDate.getTime());
    expect(result.created).not.toBe(sourceDate);
    expect(result.created).not.toBe(targetDate);

    sourceDate.setFullYear(2030);
    expect((result.created as Date).getTime()).toBe(new Date("2024-05-06T07:08:09.000Z").getTime());
  });

  it("supports symbol keys, including recursive merge on symbol-keyed objects", () => {
    const symTop = Symbol("top");
    const symNested = Symbol("nested");

    const target = {
      [symTop]: {
        a: 1,
        [symNested]: {
          left: "keep",
        },
      },
      regular: 1,
    };

    const source = {
      [symTop]: {
        b: 2,
        [symNested]: {
          right: "add",
        },
      },
    };

    const result = deepMerge(target, source);

    expect(result.regular).toBe(1);
    expect(result[symTop]).toEqual({
      a: 1,
      b: 2,
      [symNested]: {
        left: "keep",
        right: "add",
      },
    });
    expect((result[symTop] as Record<string | symbol, unknown>)[symNested]).toEqual({
      left: "keep",
      right: "add",
    });
  });

  it("skips undefined values from source and preserves target values", () => {
    const target = {
      keepNumber: 1,
      keepObject: { a: 1 },
      missing: "present",
    };

    const source = {
      keepNumber: undefined,
      keepObject: undefined,
      newUndefined: undefined,
      missing: undefined,
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      keepNumber: 1,
      keepObject: { a: 1 },
      missing: "present",
    });
    expect("newUndefined" in result).toBe(false);
  });

  it("allows null in source to replace any target value", () => {
    const target = {
      a: 1,
      nested: { value: true },
      arr: [1, 2],
    };

    const source = {
      a: null,
      nested: null,
      arr: null,
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      a: null,
      nested: null,
      arr: null,
    });
  });

  it("skips forbidden prototype pollution keys and does not pollute Object.prototype", () => {
    const target = { safe: true };
    const source = JSON.parse(
      '{"__proto__":{"polluted":"yes"},"constructor":{"prototype":{"bad":1}},"prototype":{"alsoBad":2},"ok":123}'
    ) as Record<string, unknown>;

    const result = deepMerge(target, source);

    expect(result).toEqual({ safe: true, ok: 123 });
    expect(Object.prototype).not.toHaveProperty("polluted");
    expect(Object.prototype).not.toHaveProperty("bad");
    expect(Object.prototype).not.toHaveProperty("alsoBad");
    expect(({} as Record<string, unknown>).polluted).toBeUndefined();
  });

  it("does not recursively merge when target value is not a plain object", () => {
    const sourceObj = { inner: "value" };

    const target1 = { value: 1 };
    const result1 = deepMerge(target1, { value: sourceObj });
    expect(result1.value).toBe(sourceObj);

    const target2 = { value: [1, 2, 3] };
    const result2 = deepMerge(target2, { value: { replaced: true } });
    expect(result2.value).toEqual({ replaced: true });
    expect(result2.value).toBe(sourceObj === result2.value ? sourceObj : result2.value);
  });

  it("does not recursively merge when source value is not a plain object", () => {
    const date = new Date("2022-02-02T02:02:02.000Z");

    const targetArray = { value: { a: 1 } };
    const resultArray = deepMerge(targetArray, { value: [9, 8, 7] as unknown as { a: number } });
    expect(resultArray.value).toEqual([9, 8, 7]);

    const targetDate = { value: { a: 1 } };
    const resultDate = deepMerge(targetDate, { value: date as unknown as { a: number } });
    expect(resultDate.value).toBeInstanceOf(Date);
    expect((resultDate.value as unknown as Date).getTime()).toBe(date.getTime());
    expect(resultDate.value).not.toBe(date);
  });

  it("treats objects with null prototype as plain objects and merges them", () => {
    const targetInner = Object.create(null) as Record<string, unknown>;
    targetInner.a = 1;

    const sourceInner = Object.create(null) as Record<string, unknown>;
    sourceInner.b = 2;

    const target = { data: targetInner };
    const source = { data: sourceInner };

    const result = deepMerge(target, source);

    expect(Object.getPrototypeOf(result.data)).toBeNull();
    expect(result.data).toEqual({ a: 1, b: 2 });
    expect(result.data).not.toBe(targetInner);
  });

  it("replaces with non-plain objects by reference when not specially handled", () => {
    class Box {
      constructor(public value: number) {}
    }

    const box = new Box(5);
    const target = { item: { old: true } };
    const source = { item: box as unknown as { old: boolean } };

    const result = deepMerge(target, source);

    expect(result.item).toBe(box);
    expect(result.item).toBeInstanceOf(Box);
  });

  it("preserves target nested object when source nested property is undefined during recursive merge", () => {
    const target = {
      nested: {
        keep: 1,
        change: 2,
      },
    };

    const source = {
      nested: {
        keep: undefined,
        change: 3,
      },
    };

    const result = deepMerge(target, source);

    expect(result).toEqual({
      nested: {
        keep: 1,
        change: 3,
      },
    });
  });
});
